from dataclasses import dataclass
import json
from pydantic_evals.evaluators import Evaluator, EvaluatorContext, EvaluationReason
from typing import Any

@dataclass(repr=False)
class ValidJSON(Evaluator[Any, Any, Any]):
    """Check if the output is valid JSON."""

    def evaluate(self, ctx: EvaluatorContext[Any, Any, Any]) -> EvaluationReason:
        try:
            # Try parse as JSON if output is a string
            if isinstance(ctx.output, str):
                json.loads(ctx.output)
                return EvaluationReason(value=True)
            # Output is already a dict/list, which is JSON-serializable
            elif isinstance(ctx.output, (dict, list)):
                # Try to serialize it back to verify
                _ = json.dumps(ctx.output)
                return EvaluationReason(value=True)
            else:
                return EvaluationReason(
                    value=False,
                    reason=f'Output is not JSON-serializable: {type(ctx.output).__name__}'
                )
        except json.JSONDecodeError as e:
            return EvaluationReason(
                value=False,
                reason=f'Invalid JSON: {e}'
            )
